# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, id, balance=0):
        self.id = id
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            return False

    def withdrawal(self, amount):
        if 0 < amount <= self.balance:
            self.balance -= amount
            return True
        else:
            return False

def process_transactions(accounts, transactions):
    for transaction in transactions:
        account = next((a for a in accounts if a.id == transaction['account']), None)
        if account and (transaction['type'].lower() == 'deposit' or transaction['type'].lower() == 'withdrawal') :
            if (transaction['type'].lower() == 'deposit'):
                account.deposit(transaction['amount'])
            elif (transaction['type'].lower() == 'withdrawal'):
                account.withdrawal(transaction['amount'])
        else:
            print('Invalid transaction')